import{_ as a,o as e,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Activation Migration Guide","description":"","frontmatter":{"title":"Activation Migration Guide","slug":"activation-migration-guide"},"headers":[],"relativePath":"marketer-hub/activation-migration-guide.md","filePath":"marketer-hub/activation-migration-guide.md"}'),i={name:"marketer-hub/activation-migration-guide.md"};function n(s,t,d,l,h,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Welcome to <a href="https://help.branch.io/docs/products#activation" target="_blank" rel="noreferrer">Branch Activation</a>, our enterprise solution for creating custom QR Codes and Short Links to activate customers across web and app.</p><p>With Activation, you can create shortened web and app links, as well as custom QR codes, that leverage the full power of the Branch Growth Platform.</p><p>Activation simplifies how you generate branded web links, app links, and QR codes, providing dedicated click insights and exports without requiring complex SDK setups for your web campaigns.</p><p>The information and resources in this guide will help you:</p><ul><li>Migrate your existing links from another service to Branch</li><li>Test and manage your links</li><li>View and export your data</li></ul><h3 id="how-branch-links-work" tabindex="-1">How Branch Links work <a class="header-anchor" href="#how-branch-links-work" aria-label="Permalink to &quot;How Branch Links work&quot;">​</a></h3><p>Web Links are web-only Short Links that work everywhere. App Links are deep links that take users to specific pages in your app. Web and App Links look the same (yourbrand.com/slug or yourbrand.app.link/slug) depending on if you choose to use a custom domain or a Branch-provided app.link domain.</p><h4 id="expected-behavior-for-web-links" tabindex="-1">Expected behavior for Web Links <a class="header-anchor" href="#expected-behavior-for-web-links" aria-label="Permalink to &quot;Expected behavior for Web Links&quot;">​</a></h4><p>If your end user does <strong>not</strong> have your app installed, or if you don’t have an app, the link will open in their default web browser. If they do have your app downloaded, the link will open in your app through an in-app web view.</p><h4 id="expected-behavior-for-app-links" tabindex="-1">Expected behavior for App Links <a class="header-anchor" href="#expected-behavior-for-app-links" aria-label="Permalink to &quot;Expected behavior for App Links&quot;">​</a></h4><p>If your end user has your app installed, the App Link will deep link to the specific app page you’ve chosen. If they do <strong>not</strong> have your app installed, they will taken to the redirect destination for non-app users which can be configured as a web page, a Branch Deepview, or the app store listing to download the app.</p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><h4 id="determine-your-scenario" tabindex="-1">Determine your scenario <a class="header-anchor" href="#determine-your-scenario" aria-label="Permalink to &quot;Determine your scenario&quot;">​</a></h4><p>Complete the following tasks to determine the correct migration scenario for your use case:</p><ol><li>Identify whether you will be using a custom domain or the Branch provided app.link domain. Read the “Add a custom domain” section below if you plan to use a custom domain.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>The steps in this article only apply to links using a custom domain that you own. Branch does not support migrating links that use a domain that you don’t own (for example, bit.ly). Links that do not use a custom domain that you own must be recreated in Branch using the provide app.link domain or a custom domain.</p></div></div><p>:::</p><ol start="2"><li>Identify the types of links you will be migrating: web links. app links, or both. Read the “How Branch Links work” section above to learn more about each link type. If migrating app links, the Branch SDK is a required component to enable deep linking into your app.</li></ol><h4 id="set-up-your-branch-dashboard" tabindex="-1">Set up your Branch Dashboard <a class="header-anchor" href="#set-up-your-branch-dashboard" aria-label="Permalink to &quot;Set up your Branch Dashboard&quot;">​</a></h4><p>Get a new Branch Dashboard (if you’re a new user) or use your existing Branch Dashboard (if you’re an existing user). If you need a new Branch Dashboard, reach out to your Branch Account Owner to create a separate dashboard for migrated Branch Links.</p><h4 id="add-a-custom-domain-optional" tabindex="-1">Add a custom domain (optional) <a class="header-anchor" href="#add-a-custom-domain-optional" aria-label="Permalink to &quot;Add a custom domain (optional)&quot;">​</a></h4><p>Read our <a href="https://help.branch.io/docs/basic-link-configuration#change-link-domain" target="_blank" rel="noreferrer">Basic Link Configuration</a> article to learn how to set up a custom domain to use for Branch Links.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>SSL certificate setup will cause about 5 minutes of downtime where users will see an error page, followed by temporarily redirecting to the default domain.</p></div><h2 id="migrate-your-links" tabindex="-1">Migrate your links <a class="header-anchor" href="#migrate-your-links" aria-label="Permalink to &quot;Migrate your links&quot;">​</a></h2><p>Complete the steps in this section to migrate your links to Branch.</p><h3 id="step-1-export-your-links-to-a-csv" tabindex="-1">Step 1: Export your links to a CSV <a class="header-anchor" href="#step-1-export-your-links-to-a-csv" aria-label="Permalink to &quot;Step 1: Export your links to a CSV&quot;">​</a></h3><p>Export the links that are stored in your existing linking service. Transfer these links to a Branch-compliant CSV or change the existing CSV to align with the fields in the sample CSV below.</p><p>Bulk Link Creation</p><p>223 Byte</p><h3 id="step-2-import-your-links-to-branch" tabindex="-1">Step 2: Import your links to Branch <a class="header-anchor" href="#step-2-import-your-links-to-branch" aria-label="Permalink to &quot;Step 2: Import your links to Branch&quot;">​</a></h3><p>Branch supports two migration paths. We recommend using the self-serve path shown in this guide if a 5-15 minute downtime is possible. Generating a CSR and updating the certificate (zero downtime) will involve Branch support and may take time.</p><p>The steps in this article only apply to links using a custom domain that you own. Branch does not support migrating links that use a domain that you don’t own (for example, bit.ly). Links that do not use a custom domain that you own must be recreated in Branch using the provide app.link domain or a custom domain.</p><p>Upload your CSV to Branch using “Method 2: Bulk Short Links in the Branch Dashboard” in our <a href="./create-app-links.html">Create Web Links</a> article. You can create both app and web links using the same method.</p><p>Alternatively, you can <a href="./create-web-links.html">create individual links in the Branch Dashboard</a> or use the <a href="https://help.branch.io/apidocs/deep-linking-api" target="_blank" rel="noreferrer">Deep Linking API</a> to create links programmatically (requires developer support).</p><h3 id="step-3-test-your-links" tabindex="-1">Step 3: Test your links <a class="header-anchor" href="#step-3-test-your-links" aria-label="Permalink to &quot;Step 3: Test your links&quot;">​</a></h3><p>Use <a href="./link-validator.html">Link Validator</a> to test how your links will behave based on who your end user is and where they are clicking the link from.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Once you’ve confirmed that your Branch Links are working and your links from your other service are no longer receiving traffic, you can deprecate them in that service.</p></div><h2 id="export-campaign-data" tabindex="-1">Export campaign data <a class="header-anchor" href="#export-campaign-data" aria-label="Permalink to &quot;Export campaign data&quot;">​</a></h2><p>With Activation, you can export your campaign data using Dashboard Exports, Branch’s Advanced Data Feeds, or one of the APIs included in your package.</p><h4 id="branch-dashboard" tabindex="-1">Branch Dashboard <a class="header-anchor" href="#branch-dashboard" aria-label="Permalink to &quot;Branch Dashboard&quot;">​</a></h4><p>Export data as a CSV or JSON file manually from the Branch Dashboard using <a href="./dashboard-exports.html">Dashboard Exports</a>. Choose between Daily or Custom exports to identify the best configuration of your export.</p><h4 id="included-apis" tabindex="-1">Included APIs <a class="header-anchor" href="#included-apis" aria-label="Permalink to &quot;Included APIs&quot;">​</a></h4><p>Activation includes the <a href="https://help.branch.io/apidocs/daily-exports-api" target="_blank" rel="noreferrer">Daily Exports API</a>, <a href="https://help.branch.io/apidocs/custom-exports-api" target="_blank" rel="noreferrer">Custom Exports API</a>, <a href="https://help.branch.io/apidocs/query-api" target="_blank" rel="noreferrer">Query API</a>, <a href="https://help.branch.io/apidocs/aggregate-api" target="_blank" rel="noreferrer">Aggregate API</a>, and <a href="https://help.branch.io/apidocs/cohort-api" target="_blank" rel="noreferrer">Cohort API</a>. Use these APIs to export specific data and analytics.</p><details><summary>Available export fields</summary><p>The following table shows the export fields that are available with Activation:</p><table tabindex="0"><thead><tr><th>Field name</th></tr></thead><tbody><tr><td>di_match_click_token</td></tr><tr><td>event_timestamp</td></tr><tr><td>hash_version</td></tr><tr><td>id</td></tr><tr><td>last_attributed_touch_data_custom_fields</td></tr><tr><td>last_attributed_touch_data_dollar_marketing_title</td></tr><tr><td>last_attributed_touch_data_plus_current_feature</td></tr><tr><td>last_attributed_touch_data_plus_touch_id</td></tr><tr><td>last_attributed_touch_data_plus_url</td></tr><tr><td>last_attributed_touch_data_plus_via_features</td></tr><tr><td>last_attributed_touch_data_plus_web_format</td></tr><tr><td>last_attributed_touch_data_tilde_campaign</td></tr><tr><td>last_attributed_touch_data_tilde_campaign_id</td></tr><tr><td>last_attributed_touch_data_tilde_campaign_type</td></tr><tr><td>last_attributed_touch_data_tilde_channel</td></tr><tr><td>last_attributed_touch_data_tilde_customer_campaign</td></tr><tr><td>last_attributed_touch_data_tilde_feature</td></tr><tr><td>last_attributed_touch_data_tilde_id</td></tr><tr><td>last_attributed_touch_data_tilde_keyword</td></tr><tr><td>last_attributed_touch_data_tilde_keyword_id</td></tr><tr><td>last_attributed_touch_data_tilde_keyword_match_type</td></tr><tr><td>last_attributed_touch_data_tilde_placement</td></tr><tr><td>last_attributed_touch_data_tilde_stage</td></tr><tr><td>last_attributed_touch_data_tilde_tags</td></tr><tr><td>last_attributed_touch_timestamp</td></tr><tr><td>last_attributed_touch_timestamp_iso</td></tr><tr><td>name</td></tr><tr><td>origin</td></tr><tr><td>request_id</td></tr><tr><td>timestamp</td></tr><tr><td>timestamp_iso</td></tr><tr><td>user_data_brand</td></tr><tr><td>user_data_browser</td></tr><tr><td>user_data_build</td></tr><tr><td>user_data_cpu_type</td></tr><tr><td>user_data_cross_platform_id</td></tr><tr><td>user_data_developer_identity</td></tr><tr><td>user_data_environment</td></tr><tr><td>user_data_geo_city_code</td></tr><tr><td>user_data_geo_city_en</td></tr><tr><td>user_data_geo_country_code</td></tr><tr><td>user_data_geo_dma_code</td></tr><tr><td>user_data_http_referrer</td></tr><tr><td>user_data_installer_package_name</td></tr><tr><td>user_data_internet_connection_type</td></tr><tr><td>user_data_ip</td></tr><tr><td>user_data_language</td></tr><tr><td>user_data_limit_ad_tracking</td></tr><tr><td>user_data_model</td></tr><tr><td>user_data_opted_in</td></tr><tr><td>user_data_os</td></tr><tr><td>user_data_os_version</td></tr><tr><td>user_data_os_version_android</td></tr><tr><td>user_data_past_cross_platform_ids</td></tr><tr><td>user_data_platform</td></tr><tr><td>user_data_prob_cross_platform_ids</td></tr><tr><td>user_data_screen_height</td></tr><tr><td>user_data_screen_width</td></tr><tr><td>user_data_user_agent</td></tr></tbody></table></details><h4 id="advanced-data-feeds" tabindex="-1">Advanced Data Feeds <a class="header-anchor" href="#advanced-data-feeds" aria-label="Permalink to &quot;Advanced Data Feeds&quot;">​</a></h4><p><a href="./data-feeds-overview.html">Advanced Data Feeds</a> is Branch’s suite of tools for exporting data which can be added on to any Branch <a href="./packaging.html">package</a>. Use these tools if you want to export your data to other analytics services.</p><p>To explore these concepts further, check out these blog posts:</p><ul><li><a href="https://www.branch.io/resources/blog/which-branch-data-export-solution-should-i-use-2/" target="_blank" rel="noreferrer">Which Branch Data Export Solution Should I Use?</a></li><li><a href="https://www.branch.io/resources/blog/10-essential-tips-for-leveraging-branchs-analytics-capabilities/" target="_blank" rel="noreferrer">10 Essential Tips for Leveraging Branch’s Analytics Capabilities</a></li></ul><h2 id="manage-and-maintain-links" tabindex="-1">Manage and maintain links <a class="header-anchor" href="#manage-and-maintain-links" aria-label="Permalink to &quot;Manage and maintain links&quot;">​</a></h2><p>Use <a href="./linkhub.html">LinkHub</a> to create, manage, and deploy links at scale. You can also view click analytics for your links on the <a href="./branch-summary-page.html">Overview</a> page.</p><p>Use <a href="./link-templates.html">Link Templates</a> to manage the bulk creation of your app and web Short Links. A Link Template can be used to automatically apply attributes while creating Short Links. This can save you time and reduce the potential for errors when creating Short Links.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>I am currently using links under a domain that I don’t own. Can I migrate those links to Branch?</summary><p>No. You cannot migrate any links that use a domain that you don&#39;t have ownership of (for example, bit.ly). Links from a domain you don’t own would need to be recreated as Branch Links with an app.link or custom domain.</p></details><details><summary>Will my existing link analytics carry over to Branch?</summary><p>No. Link analytics for your Branch Links will begin as soon as they’re created.</p></details><details><summary>Can I migrate my shortened links from a different tool to the same Branch Dashboard I already use for existing Branch campaigns?</summary><p>Yes. You can use the same Branch Dashboard. Review the following examples to learn more about what to expect.</p><table tabindex="0"><thead><tr><th>Change</th><th>Example</th><th>Behavior</th></tr></thead><tbody><tr><td>App.link to custom domain</td><td><strong>yourbrand.app.link</strong> to <strong>yourbrand.com</strong></td><td>- Existing app.link links will work - You must add the new domain to the app code for the new links to work - You must release a new version of your app</td></tr><tr><td>Custom domain to custom domain</td><td><strong>app.youbrand.com</strong> to <strong>yourbrand.com</strong></td><td>- Existing links will break - You must add the new domain to the app code for the new links to work - You must release a new version of your app</td></tr></tbody></table></details><details><summary>What should I do if I don’t have the team or resources needed to implement Activation?</summary><p>If your team lacks the capacity or expertise to implement the solution, our <a href="https://www.branch.io/professional-services/" target="_blank" rel="noreferrer">Professional Services</a> team can provide hands-on, tailored support to ensure a successful deployment from start to finish. We offer advisory hours to give you access to our consultants for strategic guidance, technical support, or specific project deliverables.</p></details><h2 id="get-professional-services-support" tabindex="-1">Get Professional Services support <a class="header-anchor" href="#get-professional-services-support" aria-label="Permalink to &quot;Get Professional Services support&quot;">​</a></h2><p>Branch’s <a href="https://www.branch.io/professional-services/" target="_blank" rel="noreferrer">Professional Services</a> team is available on a paid basis for your onboarding setup and advisory, implementation enhancement, and large strategic project execution needs. Reach out to your Branch Account Owner for more information on how Professional Services can support your Activation product usage.</p>',59)])])}const m=a(i,[["render",n]]);export{p as __pageData,m as default};
